import { createTypedLink } from "@/lib/params-utils";
import { ColumnFiltersState, type SortingState } from "@tanstack/react-table";
import { ParserMap, useQueryStates } from "nuqs";
import { createLoader, inferParserType, parseAsInteger, parseAsJson, parseAsString, SearchParams, UrlKeys } from "nuqs/server";

export const baseSearchParams = {
  limit: parseAsInteger.withDefault(10),
  skip: parseAsInteger.withDefault(0),
  sort: parseAsJson<SortingState>((value) => value as SortingState).withDefault([]),
  globalFilter: parseAsString.withDefault(""),
  columnFilters: parseAsJson<ColumnFiltersState>((value) => value as ColumnFiltersState).withDefault([]),
} as const;

export const baseUrlKeys = {
  limit: "paginate",
  skip: "skip",
  globalFilter: "q",
  columnFilters: "filters",
} as const;


export function createParams<T extends ParserMap>(
  extraParams: T,
  extraUrlKeys?: UrlKeys<T>,
  options?: Omit<Parameters<typeof useQueryStates>[1], "urlKeys">,
) {
  const mergedParams = { ...baseSearchParams, ...extraParams } as typeof baseSearchParams & T;
  const mergedUrlKeys = { ...baseUrlKeys, ...extraUrlKeys } as UrlKeys<typeof mergedParams>;

  type LoadSearchParams = (input: Promise<SearchParams> | SearchParams) => Promise<inferParserType<typeof mergedParams>>;

  const loadSearchParams = createLoader(mergedParams, {
    urlKeys: mergedUrlKeys,
  }) as LoadSearchParams;

  function useSearchParams() {
    return useQueryStates(mergedParams, {
      urlKeys: mergedUrlKeys,
      shallow: false,
      ...options,
    }) as ReturnType<typeof useQueryStates<typeof mergedParams>>;
  }

  return {
    searchParams: mergedParams,
    urlKeys: mergedUrlKeys,
    loadSearchParams,
    useSearchParams,
  };
}

export const { searchParams, urlKeys, loadSearchParams, useSearchParams } = createParams({});

export const getBaseSearchLinks = createTypedLink("/", baseSearchParams, { urlKeys: baseUrlKeys });

import type { Route } from "next";
import { createSerializer, type CreateSerializerOptions, type ParserMap } from "nuqs/server";

export function createTypedLink<Parsers extends ParserMap>(route: Route, parsers: Parsers, options: CreateSerializerOptions<Parsers> = {}) {
  const serialize = createSerializer<Parsers, Route, Route>(parsers, options);
  return serialize.bind(null, route);
}

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { Column } from "@tanstack/react-table";
import { ArrowDown, ArrowUp, ChevronsUpDown, EyeOff, X } from "lucide-react";

import { useSearchParams } from "@/lib/search-params";

type DataTableColumnHeaderProps<TData, TValue> = {
  column: Column<TData, TValue>;
  title: string;
} & React.HTMLAttributes<HTMLDivElement>;

export function DataTableColumnHeader<TData, TValue>({ column, title, className }: DataTableColumnHeaderProps<TData, TValue>) {
  const [{ sort }, setSort] = useSearchParams();

  if (!column.getCanSort()) {
    return <div className={cn(className)}>{title}</div>;
  }

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button variant="ghost" size="sm" className="data-[state=open]:bg-accent -ml-3 h-8">
            <span>{title}</span>
            {column.getIsSorted() === "desc" ? <ArrowDown /> : column.getIsSorted() === "asc" ? <ArrowUp /> : <ChevronsUpDown />}
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">
          <DropdownMenuItem
            onClick={() => {
              if (sort.some((s) => s.id === column.id && s.desc === false)) return;

              setSort({
                sort: [
                  ...sort.filter((s) => s.id !== column.id),
                  {
                    id: column.id,
                    desc: false,
                  },
                ],
              });
            }}
          >
            <ArrowUp />
            Asc
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={() => {
              if (sort.some((s) => s.id === column.id && s.desc === true)) return;
              setSort({
                sort: [
                  ...sort.filter((s) => s.id !== column.id),
                  {
                    id: column.id,
                    desc: true,
                  },
                ],
              });
            }}
          >
            <ArrowDown />
            Desc
          </DropdownMenuItem>
          {column.getIsSorted() && (
            <DropdownMenuItem
              onClick={() => {
                setSort({
                  sort: [...sort.filter((s) => s.id !== column.id)],
                });
              }}
            >
              <X />
              Reset
            </DropdownMenuItem>
          )}
          <DropdownMenuSeparator />
          <DropdownMenuItem onClick={() => column.toggleVisibility(false)}>
            <EyeOff />
            Hide
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";
import { useSearchParams } from "@/lib/search-params";
import { cn } from "@/lib/utils";
import type { Column } from "@tanstack/react-table";
import { format, getTime, isValid } from "date-fns";
import { CalendarIcon, XCircle } from "lucide-react";
import z from "zod";

type DateFilterProps<TData, TValue> = {
  column?: Column<TData, TValue>;
  title: string;
  className?: string;
};

const isValidString = z.string().default("");

export function DataTableDate<TData, TValue>({ column, title, className }: DateFilterProps<TData, TValue>) {
  const [{ columnFilters }, setFilters] = useSearchParams();

  const currentColumn = columnFilters.find((c) => c.id === column?.id);
  const value = isValidString.parse(currentColumn?.value);

  const [fromStr, toStr] = value.split(",");
  const fromDate = fromStr ? new Date(Number(fromStr)) : undefined;
  const toDate = toStr ? new Date(Number(toStr)) : undefined;

  const hasValidFrom = fromDate && isValid(fromDate);
  const hasValidTo = toDate && isValid(toDate);
  const haveValue = hasValidFrom || hasValidTo;

  return (
    <div className={cn("grid gap-2", className)}>
      <Popover>
        <PopoverTrigger asChild>
          <Button id="date" variant={"outline"} className={cn("justify-start text-left font-normal border-dashed h-8")}>
            {haveValue && (
              <div
                role="button"
                aria-label="Clear Created At filter"
                className="rounded-sm opacity-70 transition-opacity hover:opacity-100 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring hover:cursor-pointer"
                onClick={() => {
                  setFilters({ columnFilters: [...columnFilters.filter((c) => c.id !== column?.id)] });
                }}
              >
                <XCircle width={24} height={24} />
              </div>
            )}
            {!haveValue && <CalendarIcon />}
            <span>{title}</span>
            {haveValue ? <Separator orientation="vertical" className="w-2 h-2" /> : null}
            {hasValidFrom ? (
              hasValidTo ? (
                <>
                  {format(fromDate, "LLL dd, y")} - {format(toDate, "LLL dd, y")}
                </>
              ) : (
                format(fromDate, "LLL dd, y")
              )
            ) : null}
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-auto p-0" align="start">
          <Calendar
            mode="range"
            selected={{
              from: hasValidFrom ? fromDate : undefined,
              to: hasValidTo ? toDate : undefined,
            }}
            onSelect={(event) => {
              const timestamps = [event?.from, event?.to].filter((a) => a !== undefined).map((a) => getTime(a));

              if (timestamps.length === 0) {
                setFilters({
                  columnFilters: columnFilters.filter((c) => c.id !== column?.id),
                });
                return;
              }

              setFilters({
                columnFilters: [
                  ...columnFilters.filter((c) => c.id !== column?.id),
                  {
                    id: column?.id as string,
                    value: timestamps.join(","),
                  },
                ],
              });
            }}
            numberOfMonths={1}
          />
        </PopoverContent>
      </Popover>
    </div>
  );
}

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList, CommandSeparator } from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";
import { useSearchParams } from "@/lib/search-params";
import { cn } from "@/lib/utils";
import type { Column } from "@tanstack/react-table";
import { Check, PlusCircle } from "lucide-react";

type DataTableFacetedFilterProps<TData, TValue> = {
  column?: Column<TData, TValue>;
  title?: string;
  options: {
    label: string;
    value: string;
    icon?: React.ComponentType<{ className?: string }>;
  }[];
};

export function DataTableFacetedFilter<TData, TValue>({ column, title, options }: DataTableFacetedFilterProps<TData, TValue>) {
  const [{ columnFilters }, setFilters] = useSearchParams();
  const currentFilter = columnFilters.find((c) => c.id === column?.id);

  const optionValues = options.map((opt) => opt.value);
  const selectedValues = new Set(
    currentFilter?.value
      ? String(currentFilter.value)
          .split(",")
          .filter((s) => optionValues.includes(s))
      : [],
  );
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" className="h-8 border-dashed">
          <PlusCircle />
          {title}
          {selectedValues?.size > 0 && (
            <>
              <Separator orientation="vertical" className="mx-2 h-4" />
              <Badge variant="secondary" className="rounded-sm px-1 font-normal lg:hidden">
                {selectedValues.size}
              </Badge>
              <div className="hidden gap-1 lg:flex">
                {selectedValues.size > 2 ? (
                  <Badge variant="secondary" className="rounded-sm px-1 font-normal">
                    {selectedValues.size} selected
                  </Badge>
                ) : (
                  options
                    .filter((option) => selectedValues.has(option.value))
                    .map((option) => (
                      <Badge variant="secondary" key={option.value} className="rounded-sm px-1 font-normal">
                        {option.label}
                      </Badge>
                    ))
                )}
              </div>
            </>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-50 p-0" align="start">
        <Command>
          <CommandInput placeholder={title} />
          <CommandList>
            <CommandEmpty>No results found.</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const isSelected = selectedValues.has(option.value);
                return (
                  <CommandItem
                    key={option.value}
                    onSelect={() => {
                      if (isSelected) {
                        selectedValues.delete(option.value);
                      } else {
                        selectedValues.add(option.value);
                      }
                      const filterValues = Array.from(selectedValues);

                      if (filterValues.length > 0) {
                        setFilters({
                          columnFilters: [
                            ...columnFilters.filter((c) => c.id !== column?.id),
                            { id: column?.id as string, value: filterValues.join(",") },
                          ],
                        });
                      } else {
                        setFilters({
                          columnFilters: columnFilters.filter((c) => c.id !== column?.id),
                        });
                      }
                    }}
                  >
                    <div
                      className={cn(
                        "flex size-4 items-center justify-center rounded-lg border",
                        isSelected ? "bg-primary border-primary text-primary-foreground" : "border-input [&_svg]:invisible",
                      )}
                    >
                      <Check className="text-primary-foreground size-3.5" />
                    </div>
                    {option.icon && <option.icon className="text-muted-foreground size-4" />}
                    <span>{option.label}</span>
                    {/* {facets?.get(option.value) && (
                      <span className="text-muted-foreground ml-auto flex size-4 items-center justify-center font-mono text-xs">

                        {facets.get(option.value)}
                      </span>
                    )} */}
                  </CommandItem>
                );
              })}
            </CommandGroup>
            {selectedValues.size > 0 && (
              <>
                <CommandSeparator />
                <CommandGroup>
                  <CommandItem
                    onSelect={() => {
                      setFilters({
                        columnFilters: columnFilters.filter((c) => c.id !== column?.id),
                      });
                    }}
                    className="justify-center text-center"
                  >
                    Clear filters
                  </CommandItem>
                </CommandGroup>
              </>
            )}
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
}

import type { Table } from "@tanstack/react-table";

export default function DataTableFooterDetails<T>({ table }: { table: Table<T> }) {
  return (
    <div className="text-muted-foreground flex-1 text-sm">
      {table.getFilteredSelectedRowModel().rows.length} of {table.getFilteredRowModel().rows.length} row(s) selected.
    </div>
  );
}

import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useSearchParams } from "@/lib/search-params";
import type { Table } from "@tanstack/react-table";

export function DataTablePageCount<T>({ table }: { table: Table<T> }) {
  const [{ limit }, setFilters] = useSearchParams();

  const limits = new Set([10, 20, 25, 30, 40, 50].concat([limit]));
  return (
    <div className="flex items-center space-x-2">
      <p className="text-sm font-medium">Rows per page</p>
      <Select
        value={`${table.getState().pagination.pageSize}`}
        onValueChange={(value) => {
          setFilters({ limit: Number(value) });
        }}
      >
        <SelectTrigger className="h-8 w-17.5">
          <SelectValue placeholder={table.getState().pagination.pageSize} />
        </SelectTrigger>
        <SelectContent side="top">
          {Array.from(limits)
            .sort((a, b) => a - b)
            .map((pageSize) => (
              <SelectItem key={pageSize} value={`${pageSize}`}>
                {pageSize}
              </SelectItem>
            ))}
        </SelectContent>
      </Select>
    </div>
  );
}

import { Button } from "@/components/ui/button";
import { Table } from "@tanstack/react-table";

import { useSearchParams } from "@/lib/search-params";
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from "lucide-react";

export default function DataTablePagination<T>({ table }: { table: Table<T> }) {
  const [{ limit, skip }, setFilters] = useSearchParams();
  return (
    <div className="flex items-center justify-end space-x-2 py-4">
      <Button
        variant="outline"
        size="sm"
        onClick={() => {
          setFilters({ skip: 0 });
        }}
        disabled={!table.getCanPreviousPage()}
      >
        <span className="sr-only">Go to first page</span>
        <ChevronsLeft />
      </Button>
      <Button
        variant="outline"
        size="sm"
        onClick={() => {
          const newSkip = Math.max(0, skip - limit);
          setFilters({ skip: newSkip });
        }}
        disabled={!table.getCanPreviousPage()}
      >
        <span className="sr-only">Go to previous page</span>
        <ChevronLeft />
      </Button>
      <Button
        variant="outline"
        size="sm"
        onClick={() => {
          const newSkip = skip + limit;
          setFilters({ skip: newSkip });
        }}
        disabled={!table.getCanNextPage()}
      >
        <span className="sr-only">Go to next page</span>
        <ChevronRight />
      </Button>
      <Button
        variant="outline"
        size="sm"
        onClick={() => {
          const totalRows = table.getRowCount();
          setFilters({ skip: totalRows - (totalRows % limit || limit) });
        }}
        disabled={!table.getCanNextPage()}
      >
        <span className="sr-only">Go to last page</span>
        <ChevronsRight />
      </Button>
    </div>
  );
}

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Separator } from "@/components/ui/separator";
import { Slider } from "@/components/ui/slider";
import { useSearchParams } from "@/lib/search-params";
import { cn } from "@/lib/utils";
import { Column } from "@tanstack/react-table";
import { Plus, XCircle } from "lucide-react";
import { debounce } from "nuqs/server";
import { useCallback, useMemo } from "react";
import { z } from "zod";

type SliderFilterProps<TData, TValue> = {
  column?: Column<TData, TValue>;
  title: string;
  className?: string;
  max?: number;
  min?: number;
  unit?: string;
};

const isString = z.string().default("");
const isNumber = z.coerce.number();

export function DataTableSlider<TData, TValue>({
  column,
  title,
  className,
  min = 1,
  max = 24,
  unit = "hr",
}: SliderFilterProps<TData, TValue>) {
  const [{ columnFilters }, setFilters] = useSearchParams();

  const currentColumn = useMemo(() => columnFilters.find((c) => c.id === column?.id), [columnFilters, column?.id]);

  const value = isString.parse(currentColumn?.value);
  const filterValues = value.split(",");

  const [firstNumber, secondNumber] = useMemo(() => {
    const params = filterValues
      .filter((v) => v)
      .map((val) => {
        const parsed = isNumber.safeParse(val);

        return parsed.success && !isNaN(parsed.data) ? parsed.data : undefined;
      });

    const firstNumber = params[0] ?? min;
    const secondNumber = params[1] ?? max;

    return [firstNumber, secondNumber];
  }, [filterValues, min, max]);

  const updateFilters = useCallback(
    (newValues: [number, number]) => {
      if (!column) return;

      setFilters(
        {
          columnFilters: [
            ...columnFilters.filter((c) => c.id !== column.id),
            {
              id: column.id,
              value: newValues.join(","),
            },
          ],
        },
        {
          limitUrlUpdates: newValues ? debounce(250) : undefined,
        },
      );
    },
    [column, columnFilters, setFilters],
  );

  const handleStartChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const newValue = Number(e.target.value);
      if (!column || newValue > secondNumber || newValue < min) return;
      updateFilters([newValue, secondNumber]);
    },
    [column, secondNumber, min, updateFilters],
  );

  const handleEndChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const newValue = Number(e.target.value);
      if (!column || newValue < firstNumber || newValue > max) return;
      updateFilters([firstNumber, newValue]);
    },
    [column, firstNumber, max, updateFilters],
  );

  const handleSliderChange = useCallback(
    (values: number[]) => {
      if (!column || values.length !== 2) return;
      updateFilters([values[0], values[1]]);
    },
    [column, updateFilters],
  );

  const hasValue = currentColumn?.value !== undefined;

  return (
    <div className={cn("grid gap-2", className)}>
      <Popover>
        <PopoverTrigger asChild>
          <Button id="date" variant="outline" className={cn("justify-start text-left font-normal border-dashed h-8")}>
            {currentColumn && (
              <div
                role="button"
                aria-label={`Clear ${title} filter`}
                className="rounded-sm opacity-70 transition-opacity hover:opacity-100 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring hover:cursor-pointer"
                onClick={() => {
                  if (!column) return;
                  setFilters({
                    columnFilters: columnFilters.filter((c) => c.id !== column.id),
                  });
                }}
              >
                <XCircle width={24} height={24} />
              </div>
            )}
            {!hasValue && <Plus />}
            <span>{title}</span>
            {hasValue ? <Separator orientation="vertical" className="w-2 h-2" /> : null}
            {hasValue ? (
              <>
                {firstNumber} - {secondNumber}
              </>
            ) : null}
          </Button>
        </PopoverTrigger>
        <PopoverContent className="flex items-center w-auto p-4 gap-1" align="start">
          <div className="flex flex-col gap-3">
            <p className="font-medium leading-none">{title}</p>
            <div className="flex items-center gap-4">
              <div className="relative">
                <Input
                  className="h-8 w-24 pr-8"
                  id="start"
                  type="number"
                  inputMode="numeric"
                  min={min}
                  max={max}
                  value={firstNumber}
                  onChange={handleStartChange}
                />
                <Label
                  htmlFor="start"
                  className="absolute top-0 right-0 bottom-0 flex items-center rounded-r-md bg-accent px-2 text-muted-foreground text-sm"
                >
                  {unit}
                </Label>
              </div>

              <div className="relative">
                <Input
                  className="h-8 w-24 pr-8"
                  id="end"
                  type="number"
                  inputMode="numeric"
                  min={min}
                  max={max}
                  value={secondNumber}
                  onChange={handleEndChange}
                />
                <Label
                  htmlFor="end"
                  className="absolute top-0 right-0 bottom-0 flex items-center rounded-r-md bg-accent px-2 text-muted-foreground text-sm"
                >
                  {unit}
                </Label>
              </div>
            </div>
            <Slider
              min={min}
              max={max}
              value={[firstNumber ?? min, secondNumber ?? max]}
              onValueChange={handleSliderChange}
              step={1}
              className={cn(className)}
            />

            <Button
              aria-label={`Clear ${title} filter`}
              variant="outline"
              size="sm"
              onClick={() => {
                if (!column) return;
                setFilters({
                  columnFilters: columnFilters.filter((c) => c.id !== column.id),
                });
              }}
            >
              Clear
            </Button>
          </div>
        </PopoverContent>
      </Popover>
    </div>
  );
}

"use client";

import { Check, ChevronsUpDown, Settings2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { Table } from "@tanstack/react-table";
import { useState } from "react";

type DataTableViewOptionsProps<TData> = {
  table: Table<TData>;
};

export function DataTableViewOptions<TData>({ table }: DataTableViewOptionsProps<TData>) {
  const [open, setOpen] = useState(false);

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" role="combobox" aria-expanded={open} className="ml-auto hidden h-8 lg:flex">
          <Settings2 />
          View
          <ChevronsUpDown className="opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-42 p-0">
        <Command>
          <CommandInput placeholder="Search framework..." className="h-9" />
          <CommandList>
            <CommandEmpty>nothing found.</CommandEmpty>
            <CommandGroup>
              {table
                .getAllColumns()
                .filter((column) => typeof column.accessorFn !== "undefined" && column.getCanHide())
                .map((column) => (
                  <CommandItem
                    key={column.id}
                    value={column.id}
                    onSelect={() => {
                      column.toggleVisibility();
                    }}
                    className="capitalize"
                  >
                    {column.id.replace("_", " ")}
                    <Check className={cn("ml-auto", column.getIsVisible() ? "opacity-100" : "opacity-0")} />
                  </CommandItem>
                ))}
            </CommandGroup>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
}
